/* 思考:在12小时内，时针的时间会重复。考虑这个问题，使用钟每12小时重复一次的时间概念，找出2004小时后的时间。为此，我们可以利用取模运算简化这个问题。 */
function think(num, divisor) {
  return num % divisor;
}
function answer(divisor, add) {
  return (add % divisor + think(add, divisor)) % divisor;
}
